# ============================================================================
#  PaymoneyWubby VOD Archive Downloader
# ----------------------------------------------------------------------------
#  Downloads all ~1000 archived VODs (~7.5 TB total) and saves them into a
#  tidy folder structure:   <SaveRoot>\YYYY\MM-Month\YYYY-MM-DD[_Title].mp4
# ============================================================================
#
#  #########################################################################
#  ##                                                                     ##
#  ##   >>>  EDIT THIS ONE LINE ONLY, THEN SAVE AND RUN THE SCRIPT.  <<<   ##
#  ##                                                                     ##
#  ##   Set $SaveRoot to the folder where you want the videos saved.      ##
#  ##   This is the ONLY thing you need to change. Nothing else below     ##
#  ##   needs to be touched.                                              ##
#  ##                                                                     ##
#  #########################################################################

$SaveRoot = "Y:\Paymoneywubby_VOD_archive"   # <-- CHANGE ME (e.g. "D:\Wubby" or "C:\Users\You\Videos\Wubby")

#  #########################################################################
#  ##   DO NOT EDIT ANYTHING BELOW THIS LINE.                             ##
#  #########################################################################

# --- How it works (for the curious) -------------------------------------
# Each video is stored on Cloudflare R2 and needs a short-lived signed link.
# For every file, the script asks the archive site for a fresh signed URL
# (valid 24h) and then downloads the real .mp4 with curl. The script is
# safe to stop and re-run: it skips files that are already fully downloaded.
# Requirements: Windows 10/11 (includes curl.exe). No installs needed.
# ------------------------------------------------------------------------

$ErrorActionPreference = "Stop"
$rpc = "https://archive.wubby.tv/rpc/getPresignedUrl"

