$total = $jobs.Count; $i = 0; $ok = 0; $failed = 0; $skipped = 0
Write-Host "Saving $total videos under: $SaveRoot" -ForegroundColor Cyan
foreach ($j in $jobs) {
  $i++
  $dest = Join-Path $SaveRoot $j.Rel
  $dir  = Split-Path $dest -Parent
  if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
  if ((Test-Path $dest) -and ((Get-Item $dest).Length -gt 1MB)) {
    Write-Host "[$i/$total] SKIP (already downloaded): $($j.Rel)"; $skipped++; continue
  }
  try {
    $payload = @{ json = @{ key = $j.Key } } | ConvertTo-Json -Compress
    $resp = Invoke-RestMethod -Uri $rpc -Method Post -ContentType "application/json" -Body $payload
    $url = $resp.json.videoUrl
    if (-not $url) { Write-Warning "[$i/$total] No download URL returned for $($j.Key)"; $failed++; continue }
    Write-Host "[$i/$total] Downloading -> $($j.Rel)"
    & curl.exe -L -s --fail -o $dest $url
    if ($LASTEXITCODE -ne 0) { Write-Warning "[$i/$total] Download failed (curl $LASTEXITCODE): $($j.Key)"; $failed++ } else { $ok++ }
  } catch { Write-Warning "[$i/$total] ERROR for $($j.Key): $_"; $failed++ }
}
Write-Host ""
Write-Host "Finished. Downloaded: $ok  Skipped: $skipped  Failed: $failed" -ForegroundColor Green
if ($failed -gt 0) { Write-Host "Re-run the script to retry the failed/skipped-incomplete files." -ForegroundColor Yellow }